import{_ as o,o as a,c as t,f as n}from"./chunks/framework.DSW2hAm3.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),i={name:"changelog.md"};function r(l,e,d,s,c,h){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to the Cobalt Design System will be documented on this page.</p><p>This project follows <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a> and uses <a href="https://github.com/changesets/changesets" target="_blank" rel="noreferrer">Changesets</a> to manage releases across the monorepo. Each package within the <code>@cobalt</code> npm scope is versioned independently, but this changelog tracks the overall system milestones.</p><blockquote><p>During the <code>0.x</code> phase, minor versions may include breaking changes. We will stabilize the public API before the <code>1.0</code> release.</p></blockquote><hr><h2 id="_0-1-0-2026-03-10" tabindex="-1">[0.1.0] - 2026-03-10 <a class="header-anchor" href="#_0-1-0-2026-03-10" aria-label="Permalink to &quot;[0.1.0] - 2026-03-10&quot;">​</a></h2><p><em>Initial alpha release of the Cobalt Design System.</em></p><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong><code>co-button</code> component</strong> — first production-ready web component with full variant support (<code>primary</code>, <code>secondary</code>, <code>ghost</code>, <code>danger</code>), three sizes (<code>sm</code>, <code>md</code>, <code>lg</code>), and disabled/loading states.</li><li><strong>Design tokens</strong> — complete token sets covering color, typography, spacing, elevation, motion, and breakpoints, authored in Style Dictionary format.</li><li><strong>React wrapper</strong> (<code>@cobalt/react</code>) — auto-generated React bindings for all <code>co-*</code> web components with full TypeScript definitions and prop forwarding.</li><li><strong>VitePress documentation site</strong> (<code>@cobalt/docs</code>) — searchable docs with live component previews, token reference tables, and contribution guidelines.</li><li><strong>Token build pipeline</strong> — generates CSS custom properties, SCSS variables, and ES module exports from a single token source.</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Upgraded Lit from v2 to v3 for improved SSR support and smaller bundle size.</li><li>Moved all component styles to use design tokens exclusively — no hard-coded values remain.</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Resolved an issue where <code>co-button</code> focus ring was not visible in Windows High Contrast Mode.</li><li>Corrected token naming convention to follow the <code>co-{category}-{concept}-{variant}-{state}</code> pattern consistently.</li></ul><hr><h2 id="_0-0-2-2026-02-14" tabindex="-1">[0.0.2] - 2026-02-14 <a class="header-anchor" href="#_0-0-2-2026-02-14" aria-label="Permalink to &quot;[0.0.2] - 2026-02-14&quot;">​</a></h2><p><em>Dark mode support, theming infrastructure, and interactive demos.</em></p><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Dark mode token set</strong> — semantic color tokens now resolve to light or dark palettes based on a <code>data-theme</code> attribute on the document root.</li><li><strong>Shoelace theme mapping</strong> — bridge layer that maps Cobalt design tokens to Shoelace CSS custom properties, enabling incremental adoption alongside existing Shoelace components.</li><li><strong>Interactive component demos</strong> — embedded playgrounds in the docs site powered by <code>&lt;co-demo&gt;</code>, supporting live prop editing and source code display.</li><li><strong>Color contrast checker</strong> — docs utility that validates WCAG 2.1 AA/AAA compliance for any foreground/background token pair.</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Refactored token build to support multiple theme outputs from a single source definition.</li><li>Updated the docs sidebar navigation to group pages by category.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Fixed a flash of unstyled content (FOUC) when loading components in lazy-loaded routes.</li><li>Resolved incorrect <code>font-weight</code> token values for the <code>heading-sm</code> typography scale.</li></ul><hr><h2 id="_0-0-1-2026-01-20" tabindex="-1">[0.0.1] - 2026-01-20 <a class="header-anchor" href="#_0-0-1-2026-01-20" aria-label="Permalink to &quot;[0.0.1] - 2026-01-20&quot;">​</a></h2><p><em>Project scaffolding and foundational infrastructure.</em></p><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Monorepo setup</strong> — Turborepo-based workspace with packages for <code>@cobalt/tokens</code>, <code>@cobalt/web-components</code>, <code>@cobalt/react</code>, and <code>@cobalt/docs</code>.</li><li><strong>CI/CD pipeline</strong> — GitHub Actions workflows for linting, testing, building, and publishing packages to npm on release.</li><li><strong>Initial token definitions</strong> — primitive color palette (gray, blue, green, red, yellow) and base spacing scale (<code>4px</code> increments).</li><li><strong>Development tooling</strong> — ESLint, Prettier, Stylelint, and Commitlint configurations shared across all packages.</li><li><strong>Changeset integration</strong> — automated version bumps and changelog generation via <code>@changesets/cli</code>.</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Corrected workspace dependency resolution for internal <code>@cobalt/*</code> packages when running parallel builds.</li></ul><hr><p><em>Format follows <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>.</em></p>',31)])])}const u=o(i,[["render",r]]);export{p as __pageData,u as default};
